请参考以下代码，其中矩阵的输入可以通过控制台进行输入：

```c
#include <stdio.h>

#define ROW1 3                  // 第一个矩阵的行数
#define COL1 2                  // 第一个矩阵的列数
#define ROW2 2                  // 第二个矩阵的行数
#define COL2 4                  // 第二个矩阵的列数

int main() {
    int matrix1[ROW1][COL1], matrix2[ROW2][COL2], product[ROW1][COL2];

    printf("请输入第一个 %d 行 %d 列的矩阵：\n", ROW1, COL1);
    for (int i = 0; i < ROW1; ++i) {
        for (int j = 0; j < COL1; ++j) {
            scanf("%d", &matrix1[i][j]);
        }
    }

    printf("请输入第二个 %d 行 %d 列的矩阵：\n", ROW2, COL2);
    for (int i = 0; i < ROW2; ++i) {
        for (int j = 0; j < COL2; ++j) {
            scanf("%d", &matrix2[i][j]);
        }
    }

    // 计算矩阵乘积
    for (int i = 0; i < ROW1; ++i) {
        for (int j = 0; j < COL2; ++j) {
            int sum = 0;
            for (int k = 0; k < ROW2; ++k) {
                sum += matrix1[i][k] * matrix2[k][j];
            }
            product[i][j] = sum;
        }
    }

    // 打印输出矩阵乘积
    printf("\n矩阵乘积为：\n");
    for (int i = 0; i < ROW1; ++i) {
        for (int j = 0; j < COL2; ++j) {
            printf("%d ", product[i][j]);
        }
        printf("\n");
    }

    return 0;
}
```

以上代码实现了两个矩阵的输入，以及矩阵乘法的计算和输出。需要注意的是，在计算矩阵乘积时需要三重循环，其中 i 和 j 循环分别控制乘积矩阵的行和列，k 循环控制乘法操作的进行。
